import { execFile } from "node:child_process";
import { promisify } from "node:util";

const execFileAsync = promisify(execFile);

export interface GitRunResult {
  stdout: string;
  stderr: string;
}

export type GitRunner = (args: string[], cwd: string) => Promise<GitRunResult>;

export interface SharedSyncOptions {
  sharedDir: string;
  message?: string;
  now?: Date;
  runGit?: GitRunner;
  gitUserName?: string;
  gitUserEmail?: string;
}

export interface SharedSyncResult {
  committed: boolean;
  commitMessage: string | null;
  statusBefore: string;
  pullOutput: string;
  pushOutput: string;
  retriedPush: boolean;
  pulledMarkdownFiles: string[];
}

async function defaultRunGit(args: string[], cwd: string): Promise<GitRunResult> {
  try {
    const { stdout, stderr } = await execFileAsync("git", args, {
      cwd,
      encoding: "utf8",
      timeout: 30_000,
      maxBuffer: 1024 * 1024,
    });
    return { stdout: stdout.trim(), stderr: stderr.trim() };
  } catch (err) {
    const e = err as Error & {
      stdout?: string | Buffer;
      stderr?: string | Buffer;
      code?: number | string;
    };
    const stdout = typeof e.stdout === "string" ? e.stdout : e.stdout?.toString("utf8") ?? "";
    const stderr = typeof e.stderr === "string" ? e.stderr : e.stderr?.toString("utf8") ?? "";
    const detail = [stderr.trim(), stdout.trim()].filter(Boolean).join("\n").slice(0, 2000);
    throw new Error(`git ${args.join(" ")} failed${e.code !== undefined ? ` (${e.code})` : ""}${detail ? `: ${detail}` : ""}`);
  }
}

function defaultMessage(now: Date): string {
  return `sync: ${now.toISOString().slice(0, 16)}`;
}

function compactOutput(result: GitRunResult): string {
  return [result.stdout, result.stderr].filter(Boolean).join("\n").trim();
}

function uniqueMarkdownFiles(files: string[]): string[] {
  return [...new Set(files)]
    .map((file) => file.replace(/\\/g, "/").trim())
    .filter((file) => file.endsWith(".md") && file !== "README.md")
    .sort();
}

async function listChangedMarkdownFiles(
  runGit: GitRunner,
  cwd: string,
  before: string,
  after: string,
): Promise<string[]> {
  if (!before || !after || before === after) return [];
  const diff = await runGit(["diff", "--name-only", before, after], cwd);
  return uniqueMarkdownFiles(diff.stdout.split(/\r?\n/));
}

async function readGitConfig(runGit: GitRunner, cwd: string, key: string): Promise<string | null> {
  try {
    const result = await runGit(["config", "--get", key], cwd);
    return result.stdout.trim() || null;
  } catch {
    return null;
  }
}

async function ensureCommitIdentity(opts: SharedSyncOptions, runGit: GitRunner): Promise<void> {
  const [name, email] = await Promise.all([
    readGitConfig(runGit, opts.sharedDir, "user.name"),
    readGitConfig(runGit, opts.sharedDir, "user.email"),
  ]);
  if (name && email) return;

  const fallbackName =
    opts.gitUserName?.trim() ||
    process.env.GIT_AUTHOR_NAME?.trim() ||
    process.env.GIT_COMMITTER_NAME?.trim() ||
    (await readGitConfig(runGit, process.cwd(), "user.name"));
  const fallbackEmail =
    opts.gitUserEmail?.trim() ||
    process.env.GIT_AUTHOR_EMAIL?.trim() ||
    process.env.GIT_COMMITTER_EMAIL?.trim() ||
    (await readGitConfig(runGit, process.cwd(), "user.email"));
  const targetName = name || fallbackName;
  const targetEmail = email || fallbackEmail;

  if (!targetName || !targetEmail) {
    throw new Error(
      "shared repo git identity is missing; set user.name and user.email in the bridge repo or provide GIT_AUTHOR_NAME/GIT_AUTHOR_EMAIL",
    );
  }

  if (!name) await runGit(["config", "--local", "user.name", targetName], opts.sharedDir);
  if (!email) await runGit(["config", "--local", "user.email", targetEmail], opts.sharedDir);
}

export async function syncSharedKnowledge(opts: SharedSyncOptions): Promise<SharedSyncResult> {
  const runGit = opts.runGit ?? defaultRunGit;
  const now = opts.now ?? new Date();
  const commitMessage = opts.message?.trim() || defaultMessage(now);

  const status = (await runGit(["status", "--porcelain"], opts.sharedDir)).stdout.trim();
  let committed = false;
  if (status) {
    await ensureCommitIdentity(opts, runGit);
    await runGit(["add", "-A"], opts.sharedDir);
    await runGit(["commit", "-m", commitMessage], opts.sharedDir);
    committed = true;
  }

  const pullBefore = (await runGit(["rev-parse", "HEAD"], opts.sharedDir)).stdout.trim();
  const pull = await runGit(["pull", "--rebase"], opts.sharedDir);
  const pullAfter = (await runGit(["rev-parse", "HEAD"], opts.sharedDir)).stdout.trim();
  let pulledMarkdownFiles = await listChangedMarkdownFiles(runGit, opts.sharedDir, pullBefore, pullAfter);

  let push = await tryPush(runGit, opts.sharedDir);
  let retriedPush = false;
  if (!push.ok) {
    retriedPush = true;
    const retryPullBefore = (await runGit(["rev-parse", "HEAD"], opts.sharedDir)).stdout.trim();
    await runGit(["pull", "--rebase"], opts.sharedDir);
    const retryPullAfter = (await runGit(["rev-parse", "HEAD"], opts.sharedDir)).stdout.trim();
    pulledMarkdownFiles = uniqueMarkdownFiles([
      ...pulledMarkdownFiles,
      ...(await listChangedMarkdownFiles(runGit, opts.sharedDir, retryPullBefore, retryPullAfter)),
    ]);
    push = await tryPush(runGit, opts.sharedDir);
  }
  if (!push.ok) throw push.error;

  return {
    committed,
    commitMessage: committed ? commitMessage : null,
    statusBefore: status,
    pullOutput: compactOutput(pull),
    pushOutput: compactOutput(push.result),
    retriedPush,
    pulledMarkdownFiles,
  };
}

async function tryPush(
  runGit: GitRunner,
  sharedDir: string,
): Promise<{ ok: true; result: GitRunResult } | { ok: false; error: Error }> {
  try {
    return { ok: true, result: await runGit(["push"], sharedDir) };
  } catch (err) {
    return { ok: false, error: err as Error };
  }
}

export function formatSharedSyncResult(result: SharedSyncResult): string {
  const lines = [
    "Shared sync 完成。",
    result.committed
      ? `本機變更已 commit：${result.commitMessage}`
      : "本機沒有未提交變更。",
    `Pull: ${result.pullOutput || "Already up to date."}`,
    `Push: ${result.pushOutput || "Everything up-to-date."}`,
  ];
  if (result.retriedPush) lines.push("Push 曾被遠端更新拒絕，已 rebase 後重試成功。");
  if (result.pulledMarkdownFiles.length > 0) {
    lines.push(
      `Pull 新/更新頁面（${result.pulledMarkdownFiles.length}）：`,
      ...result.pulledMarkdownFiles.map((file) => `  - ${file}`),
      "接著會請 agent 讀取這些 shared 頁面並判斷是否值得內化。",
    );
  }
  return lines.join("\n");
}

