export async function handleSharedSync(ctx: Context): Promise<void> {
  const { isAllowed } = deps();
  if (!isAllowed(ctx)) return;
  const sharedDir = path.join(config.memoryDir, "shared");
  const rawArg = typeof ctx.match === "string" ? ctx.match.trim() : "";
  try {
    const result = await syncSharedKnowledge({
      sharedDir,
      message: rawArg || undefined,
    });
    await ctx.reply(formatSharedSyncResult(result));
    await triggerSharedReview(ctx, sharedDir, result.pulledMarkdownFiles);
  } catch (err: any) {
    await ctx.reply(`⚠️ shared-sync 失敗：${err.message?.slice(0, 800)}`);
  }
}

#!/usr/bin/env node
/**
 * shared-sync.mjs — git add + commit + rebase-pull + push the shared knowledge repo.
 * Usage: MEMORY_DIR=<path> node scripts/shared-sync.mjs [message]
 * If no message provided, uses "sync: <timestamp>".
 */
import { execFileSync } from "node:child_process";
import path from "node:path";

if (!process.env.MEMORY_DIR) {
  console.error("[shared-sync] MEMORY_DIR is required; refusing to guess a machine-specific path.");
  process.exit(2);
}

const SHARED_DIR = path.join(process.env.MEMORY_DIR, "shared");

function run(args, allowFailure = false, cwd = SHARED_DIR) {
  try {
    return execFileSync("git", args, {
      cwd,
      encoding: "utf8",
      stdio: "pipe",
      timeout: 30000,
    }).trim();
  } catch (err) {
    if (allowFailure) return err;
    throw err;
  }
}

const msg = process.argv[2] || `sync: ${new Date().toISOString().slice(0, 16)}`;

function readConfig(cwd, key) {
  const value = run(["config", "--get", key], true, cwd);
  return value instanceof Error ? "" : value.trim();
}

function changedMarkdownFiles(before, after) {
  if (!before || !after || before === after) return [];
  const diff = run(["diff", "--name-only", before, after]);
  return [...new Set(diff.split(/\r?\n/))]
    .map((file) => file.replace(/\\/g, "/").trim())
    .filter((file) => file.endsWith(".md") && file !== "README.md")
    .sort();
}

function ensureCommitIdentity() {
  const sharedName = readConfig(SHARED_DIR, "user.name");
  const sharedEmail = readConfig(SHARED_DIR, "user.email");
  if (sharedName && sharedEmail) return;

  const fallbackName =
    process.env.GIT_AUTHOR_NAME?.trim() ||
    process.env.GIT_COMMITTER_NAME?.trim() ||
    readConfig(process.cwd(), "user.name");
  const fallbackEmail =
    process.env.GIT_AUTHOR_EMAIL?.trim() ||
    process.env.GIT_COMMITTER_EMAIL?.trim() ||
    readConfig(process.cwd(), "user.email");
  const targetName = sharedName || fallbackName;
  const targetEmail = sharedEmail || fallbackEmail;

  if (!targetName || !targetEmail) {
    throw new Error(
      "shared repo git identity is missing; set user.name and user.email in the bridge repo or provide GIT_AUTHOR_NAME/GIT_AUTHOR_EMAIL",
    );
  }

  if (!sharedName) run(["config", "--local", "user.name", targetName]);
  if (!sharedEmail) run(["config", "--local", "user.email", targetEmail]);
}

// Check for changes
const status = run(["status", "--porcelain"]);
if (status) {
  ensureCommitIdentity();
  run(["add", "-A"]);
  run(["commit", "-m", msg]);
  console.log(`[shared-sync] committed: ${msg}`);
} else {
  console.log("[shared-sync] no uncommitted changes");
}

const beforePull = run(["rev-parse", "HEAD"]);
run(["pull", "--rebase"]);
const afterPull = run(["rev-parse", "HEAD"]);
let pulledMarkdownFiles = changedMarkdownFiles(beforePull, afterPull);

let push = run(["push"], true);
if (push instanceof Error) {
  console.log("[shared-sync] push rejected or failed; pulling with rebase once before retry");
  const beforeRetryPull = run(["rev-parse", "HEAD"]);
  run(["pull", "--rebase"]);
  const afterRetryPull = run(["rev-parse", "HEAD"]);
  pulledMarkdownFiles = [...new Set([
    ...pulledMarkdownFiles,
    ...changedMarkdownFiles(beforeRetryPull, afterRetryPull),
  ])].sort();
  push = run(["push"], true);
}
if (push instanceof Error) throw push;
if (pulledMarkdownFiles.length > 0) {
  console.log(`[shared-sync] pulled markdown files:\n${pulledMarkdownFiles.map((file) => `  - ${file}`).join("\n")}`);
}
console.log(`[shared-sync] pushed: ${msg}`);

export async function handleSharedPull(ctx: Context): Promise<void> {
  const { isAllowed } = deps();
  if (!isAllowed(ctx)) return;
  const sharedDir = path.join(config.memoryDir, "shared");
  try {
    const { execFileSync } = await import("node:child_process");
    const git = (args: string[], timeout = 5000) =>
      execFileSync("git", args, { cwd: sharedDir, encoding: "utf8", timeout }).trim();
    const before = git(["rev-parse", "HEAD"]);
    const out = git(["pull", "--ff-only"], 30000);
    const after = git(["rev-parse", "HEAD"]);

    let newFiles: string[] = [];
    if (before !== after) {
      const diff = git(["diff", "--name-only", before, after]);
      if (diff) {
        newFiles = [...new Set(diff.split(/\r?\n/))]
          .map((f) => f.replace(/\\/g, "/").trim())
          .filter((f) => f.endsWith(".md") && f !== "README.md")
          .sort();
      }
    }

    let msg = `📥 Shared pull：${out || "Already up to date."}`;
    if (newFiles.length > 0) {
      msg += `\n\n📄 新/更新頁面（${newFiles.length}）：\n${newFiles.map((f) => `  - ${f}`).join("\n")}`;
      msg += `\n\n💡 接著會請 agent 讀取上述頁面，判斷是否值得內化為本機 memory/wiki。`;
    }
    await ctx.reply(msg);
    await triggerSharedReview(ctx, sharedDir, newFiles);
  } catch (err: any) {
    await ctx.reply(`⚠️ shared-pull 失敗：${err.message?.slice(0, 200)}`);
  }
}

// ─── /sharedsync ───────────────────────────────────────────────────────────

export async function handleSharedSync(ctx: Context): Promise<void> {
  const { isAllowed } = deps();

  const absPaths = files
    .slice(0, 20)
    .map((file) => path.join(sharedDir, file));
  const more = files.length > absPaths.length ? `\n另有 ${files.length - absPaths.length} 個檔案未列入本次自動審閱。` : "";
  return (
    `[系統] shared knowledge repo 剛 pull 到新/更新的 Markdown 頁面。\n` +
    `請逐一用 read tool 讀取下列檔案，判斷是否值得內化成本機 memory/wiki。\n\n` +
    absPaths.map((file) => `- ${file}`).join("\n") +
    more +
    `\n\n規則：\n` +
    `- 不要只憑檔名判斷；必須讀檔後再下結論。\n` +
    `- 只處理穩定、可重用、跨 session 仍有價值的知識。\n` +
    `- 若適合 memory，提出一行可 remember 的 fact，並說明 topic 建議。\n` +
    `- 若適合 wiki，提出目標 slug/type 與摘要。\n` +
    `- 若內容不適合內化，說明跳過原因。\n` +
    `- 預設先輸出候選與建議，不要靜默寫入 memory/wiki；除非內容明確是既有已批准的 shared learning。\n` +
    `- 用繁體中文回覆。`
  );
}

async function triggerSharedReview(ctx: Context, sharedDir: string, files: string[]): Promise<void> {
  if (files.length === 0) return;
  const { sessions, runPrompt } = deps();
  const chatId = ctx.chat?.id;
  if (!chatId) return;
  try {
    const session = await sessions.get(chatId, ctx.from?.id);
    await runPrompt(ctx, session, buildSharedReviewPrompt(sharedDir, files), { kind: "meta" });
  } catch (err) {
    await ctx.reply(`⚠️ shared review 啟動失敗：${(err as Error).message.slice(0, 300)}`);
  }
}

